    bool newSettingState = true;
    bool settingToggled = true;
    if(commandArgument.EndsWith(" true")){
        settingToggled = false;
    }
    else if(commandArgument.EndsWith(" false")){
        newSettingState = false;
        settingToggled = false;
    }
    if(commandArgument == "reset"){
        ResetScript();
        return true;
    }
    else if(commandArgument == "findBlueprints"){
        if(!CheckBlueprints()){
            Echo("Checked " + checkedBlueprints + " / " + totalBlueprints + " saved items.");
            return true;
        }
        else{
            statusMessage = "Checked all " + totalBlueprints + " saved items! Found " + (newBlueprintsFound - previousCount) + " new autocrafting blueprints!";
