    // E.g., for "balanceTypeContainers" command:
    else if(commandArgument.StartsWith("balanceTypeContainers")){
        statusLabel = "Balance type containers";
        if(settingToggled) newSettingState = !balanceTypeContainers;
        balanceTypeContainers = newSettingState;
    }
    // Additional commands are processed in a similar pattern...

    // After processing the command, provide feedback and optionally perform additional actions.
    else {
        executeCommand = false;
    }
    if(executeCommand){
        TimeSpan timeSinceLastCheck = DateTime.Now - lastCheckTime;
        if(statusMessage == "") statusMessage = statusLabel + " temporarily " + (newSettingState ? "enabled" : "disabled") + "!\n";
        Echo(statusMessage);
        Echo("Continuing in " + Math.Ceiling(3 - timeSinceLastCheck.TotalSeconds) + " seconds..");
        nextAction = "showCountdown";
        if(timeSinceLastCheck.TotalSeconds >= 3){
